const input = $input.first().json;

// Firefly API liefert data[] = transaction groups.
// Darin liegen echte Buchungen meistens unter attributes.transactions[].
const rawData = input.data || input.transactions || [];
const transactions = [];

for (const item of rawData) {
  const attr = item.attributes || item;

  if (Array.isArray(attr.transactions)) {
    for (const tx of attr.transactions) {
      transactions.push({
        ...tx,
        group_id: item.id || tx.group_id || '',
      });
    }
  } else {
    transactions.push({
      ...attr,
      id: item.id || attr.id || '',
    });
  }
}

// Konto optional aus dem vorherigen Node holen
let accountBalance = 0;
let accountName = 'Volksbank';
let accountId = $('Konfiguration').first().json.firefly_account_id || '112';

try {
  const accountRaw = $('Firefly Konto holen').first().json;
  const accountAttr = accountRaw.data?.attributes || {};

  accountBalance = Number(
    accountAttr.current_balance ??
    accountAttr.virtual_balance ??
    0
  );

  accountName = accountAttr.name || 'Volksbank';
  accountId = accountRaw.data?.id || accountId;
} catch (e) {
  // Wenn Konto nicht verfügbar ist, trotzdem weitermachen.
}

function escTag(v) {
  return String(v ?? 'Unbekannt')
    .replace(/\\/g, '\\\\')
    .replace(/ /g, '\\ ')
    .replace(/,/g, '\\,')
    .replace(/=/g, '\\=')
    .replace(/:/g, '\\:');
}

function escString(v) {
  return String(v ?? '')
    .replace(/\\/g, '\\\\')
    .replace(/"/g, '\\"')
    .replace(/\n/g, ' ')
    .replace(/\r/g, ' ');
}

function num(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : 0;
}

function tsFromDate(dateValue) {
  const d = new Date(dateValue);
  if (Number.isNaN(d.getTime())) {
    return Date.now() * 1000000;
  }
  return d.getTime() * 1000000;
}

const lines = [];

// Aktueller Kontostand
lines.push(
  `firefly_account,account=${escTag(accountName)},account_id=${escTag(accountId)} balance=${accountBalance} ${Date.now() * 1000000}`
);

// Firefly-Transaktionen 1:1 schreiben
for (const t of transactions) {
  const id =
    t.transaction_journal_id ||
    t.id ||
    t.internal_reference ||
    `${t.date || 'nodate'}-${t.amount || 0}-${t.description || 'nodesc'}`;

  const type = String(t.type || 'unknown').toLowerCase();

  const amount = Math.abs(num(t.amount));

  let signedAmount = amount;
  if (type === 'withdrawal') signedAmount = -amount;
  if (type === 'deposit') signedAmount = amount;
  if (type === 'transfer') signedAmount = amount;

  const date = t.date || new Date().toISOString();
  const month = String(date).slice(0, 7);
  const day = String(date).slice(0, 10);

  const category = t.category_name || t.category || 'Ohne Kategorie';
  const source = t.source_name || t.source || 'Unbekannt';
  const destination = t.destination_name || t.destination || 'Unbekannt';
  const description = t.description || 'Keine Beschreibung';

  const ts = tsFromDate(date);

  lines.push(
    `firefly_transaction,transaction_id=${escTag(id)},type=${escTag(type)},month=${escTag(month)},day=${escTag(day)},category=${escTag(category)},source=${escTag(source)},destination=${escTag(destination)} amount=${amount},signed_amount=${signedAmount},description="${escString(description)}" ${ts}`
  );
}

return [
  {
    json: {
      lineProtocol: lines.join('\n'),
      debug_lines: lines.length,
      debug_transactions: transactions.length,
      debug_account_balance: accountBalance,
      debug_bucket: $('Konfiguration').first().json.influx_bucket
    }
  }
];

const cfg = $('Konfiguration').first().json;

const lineProtocol = $json.lineProtocol;

if (!lineProtocol || typeof lineProtocol !== 'string') {
  throw new Error('Kein lineProtocol im Input gefunden.');
}

const influxUrl = String(cfg.influx_url || '').replace(/\/$/, '');
const org = encodeURIComponent(cfg.influx_org);
const bucket = encodeURIComponent(cfg.influx_bucket || 'firefly');
const token = cfg.influx_token;

const url = `${influxUrl}/api/v2/write?org=${org}&bucket=${bucket}&precision=ns`;

let responseText = '';

try {
  responseText = await this.helpers.httpRequest({
    method: 'POST',
    url,
    headers: {
      Authorization: `Token ${token}`,
      'Content-Type': 'text/plain',
      Accept: 'text/plain',
    },
    body: lineProtocol,
    json: false,
    returnFullResponse: false,
  });
} catch (error) {
  const status =
    error.response?.statusCode ||
    error.response?.status ||
    error.statusCode ||
    error.status ||
    'unknown';

  const body =
    error.response?.body ||
    error.message ||
    JSON.stringify(error);

  throw new Error(`InfluxDB Write fehlgeschlagen. HTTP ${status}: ${body}`);
}

return [
  {
    json: {
      success: true,
      written_lines: lineProtocol.split('\n').filter(Boolean).length,
      bucket: cfg.influx_bucket,
      org: cfg.influx_org,
      response: responseText || 'No Content',
    },
  },
];

